import React, { useState } from 'react';
import { User } from '../types';
import { Mail, Lock, User as UserIcon, X, Sparkles, Eye, EyeOff, AlertCircle, FileText, Zap, BookOpen, AlertTriangle } from 'lucide-react';
import { auth, googleProvider } from '../services/firebase';
import { signInWithEmailAndPassword, createUserWithEmailAndPassword, signInWithPopup, updateProfile } from 'firebase/auth';

interface AuthProps {
  isOpen: boolean;
  onClose: () => void;
  onLogin: (user: User) => void;
  triggerReason?: 'user_action' | 'limit_reached';
}

export const Auth: React.FC<AuthProps> = ({ isOpen, onClose, onLogin, triggerReason = 'user_action' }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  if (!isOpen) return null;

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError(null);

    try {
        let userCredential;

        if (isLogin) {
            // Login Real com Firebase
            userCredential = await signInWithEmailAndPassword(auth, email, password);
        } else {
            // Registo Real com Firebase
            if (password.length < 6) {
                throw new Error("auth/weak-password");
            }
            userCredential = await createUserWithEmailAndPassword(auth, email, password);

            // Atualizar nome de exibição se fornecido
            if (name && userCredential.user) {
                await updateProfile(userCredential.user, {
                    displayName: name
                });
            }
        }

        // Mapear utilizador do Firebase para o tipo User da App
        const firebaseUser = userCredential.user;
        const appUser: User = {
            id: firebaseUser.uid,
            email: firebaseUser.email || '',
            name: firebaseUser.displayName || name || email.split('@')[0] || 'Utilizador',
        };

        onLogin(appUser);

    } catch (err: any) {
        console.error("Auth Error:", err.code, err.message);

        const errorCode = err.code;

        if (errorCode === 'auth/invalid-credential' || errorCode === 'auth/user-not-found' || errorCode === 'auth/wrong-password') {
            setError("E-mail ou palavra-passe incorretos.");
        } else if (errorCode === 'auth/email-already-in-use') {
            setError("Este e-mail já está em uso.");
        } else if (errorCode === 'auth/weak-password') {
            setError("A palavra-passe deve ter pelo menos 6 caracteres.");
        } else if (errorCode === 'auth/too-many-requests') {
             setError("Muitas tentativas falhadas. Tente novamente mais tarde.");
        } else if (errorCode === 'auth/network-request-failed') {
             setError("Erro de conexão. Verifique sua internet.");
        } else {
            setError("Ocorreu um erro ao entrar. Tente novamente.");
        }
        setIsLoading(false);
    }
  };

  const handleGoogleLogin = async () => {
      setIsLoading(true);
      setError(null);

      try {
          // Tenta login com popup. 
          // Requer que o domínio atual esteja na lista "Authorized Domains" no Firebase Console.
          const result = await signInWithPopup(auth, googleProvider);
          const firebaseUser = result.user;

          const appUser: User = {
              id: firebaseUser.uid,
              email: firebaseUser.email || '',
              name: firebaseUser.displayName || 'Utilizador Google',
          };

          onLogin(appUser);
      } catch (err: any) {
          console.error("Google Auth Error:", err);
          const errorCode = err.code;

          if (errorCode === 'auth/popup-closed-by-user') {
              setError("O login foi cancelado.");
          } else if (errorCode === 'auth/popup-blocked') {
              setError("O navegador bloqueou o popup. Por favor, permita popups.");
          } else if (errorCode === 'auth/unauthorized-domain') {
              // Mensagem substituída conforme solicitado pelo usuário
              setError("A opção 'Continuar com Google' está em manutenção. Por favor, adicione seu e-mail no campo acima ou tente mais tarde.");
          } else if (errorCode === 'auth/network-request-failed') {
              setError("Erro de rede. Verifique sua conexão e tente novamente.");
          } else {
              setError(`Erro na autenticação Google. A opção pode estar em manutenção. Tente usar E-mail e Palavra-passe.`);
          }
          setIsLoading(false);
      }
  }

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in">
      <div className="bg-white dark:bg-gray-900 p-8 rounded-2xl shadow-2xl w-full max-w-[450px] border border-gray-100 dark:border-gray-800 relative overflow-hidden transition-colors flex flex-col max-h-[90vh]">

        <button 
            onClick={onClose}
            className="absolute top-4 right-4 text-gray-400 hover:text-gray-600 dark:hover:text-gray-200 transition-colors z-10"
        >
            <X size={20} />
        </button>

        <div className="overflow-y-auto custom-scrollbar">
            <div className="text-center mb-6 mt-2">
                {triggerReason === 'limit_reached' ? (
                    <div className="mb-6">
                         <div className="inline-flex justify-center mb-4">
                            <div className="bg-gradient-to-tr from-indigo-500 to-purple-600 text-white p-4 rounded-full shadow-lg shadow-indigo-500/30">
                                <Sparkles size={32} />
                            </div>
                        </div>
                        <h2 className="text-2xl font-bold text-gray-900 dark:text-white mb-2">
                            Limite Gratuito Atingido
                        </h2>
                        <p className="text-gray-600 dark:text-gray-300 text-sm mb-4 leading-relaxed">
                            Atingiu as suas 6 mensagens gratuitas. Faça login para continuar a usar o IV4 IA sem limites.
                        </p>

                        <div className="bg-gray-50 dark:bg-gray-800/50 rounded-xl p-4 text-left border border-gray-100 dark:border-gray-700/50">
                            <h3 className="text-xs font-bold text-gray-50 dark:text-gray-400 uppercase tracking-wider mb-3">Vantagens da Conta:</h3>
                            <ul className="space-y-2.5">
                                <li className="flex items-center gap-3 text-sm text-gray-700 dark:text-gray-200">
                                    <div className="bg-indigo-100 dark:bg-indigo-900/30 p-1 rounded text-indigo-600 dark:text-indigo-400"><FileText size={14}/></div>
                                    Gerador de Trabalhos Escolares
                                </li>
                                <li className="flex items-center gap-3 text-sm text-gray-700 dark:text-gray-200">
                                    <div className="bg-purple-100 dark:bg-purple-900/30 p-1 rounded text-purple-600 dark:text-purple-400"><Zap size={14}/></div>
                                    Humanizador de Texto
                                </li>
                                <li className="flex items-center gap-3 text-sm text-gray-700 dark:text-gray-200">
                                    <div className="bg-green-100 dark:bg-green-900/30 p-1 rounded text-green-600 dark:text-green-400"><BookOpen size={14}/></div>
                                    Histórico de Conversas Salvo
                                </li>
                            </ul>
                        </div>
                    </div>
                ) : (
                    <>
                        <div className="flex justify-center mb-6">
                            <div className="bg-indigo-600 text-white p-3 rounded-2xl shadow-lg shadow-indigo-200 dark:shadow-none rotate-3 hover:rotate-6 transition-transform">
                                <Sparkles size={28} />
                            </div>
                        </div>
                        <h1 className="text-2xl font-bold text-gray-900 dark:text-white mb-2">
                            {isLogin ? 'Bem-vindo de volta' : 'Criar conta'}
                        </h1>
                        <p className="text-sm text-gray-500 dark:text-gray-400">
                            {isLogin ? 'Entre na sua conta para continuar' : 'Registe-se para salvar o seu histórico'}
                        </p>
                    </>
                )}
            </div>

            {error && (
                <div className="mb-4 p-3 bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 rounded-lg flex flex-col gap-2 text-sm text-red-600 dark:text-red-400 font-medium">
                    <div className="flex items-center gap-2">
                        <AlertTriangle size={16} className="shrink-0" />
                        <span className="font-bold">Atenção:</span>
                    </div>
                    <p className="break-words leading-relaxed">{error}</p>
                </div>
            )}

            <form onSubmit={handleSubmit} className="space-y-4">
            {!isLogin && (
                <div>
                <div className="relative">
                    <input
                    type="text"
                    required
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    className="w-full px-4 py-3 bg-transparent border border-gray-300 dark:border-gray-700 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:border-transparent outline-none transition-all text-black dark:text-white placeholder-gray-500"
                    placeholder="Nome completo"
                    />
                </div>
                </div>
            )}

            <div>
                <div className="relative">
                <input
                    type="email"
                    required
                    pattern="[a-z0-9._%+-]+@[a-z0-9.-]+\.[a-z]{2,}$"
                    title="Por favor insira um endereço de email válido"
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    className="w-full px-4 py-3 bg-transparent border border-gray-300 dark:border-gray-700 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:border-transparent outline-none transition-all text-black dark:text-white placeholder-gray-500"
                    placeholder="Endereço de e-mail (Ex: nome@email.com)"
                    />
                </div>
            </div>

            <div>
                <div className="relative">
                <input
                    type={showPassword ? "text" : "password"}
                    required
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    className="w-full px-4 py-3 bg-transparent border border-gray-300 dark:border-gray-700 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:border-transparent outline-none transition-all text-black dark:text-white placeholder-gray-500 pr-10"
                    placeholder="Palavra-passe"
                />
                <button 
                    type="button"
                    onClick={() => setShowPassword(!showPassword)}
                    className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600 dark:hover:text-gray-300"
                >
                    {showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
                </button>
                </div>
            </div>

            <button
                type="submit"
                disabled={isLoading}
                className="w-full bg-indigo-600 text-white font-medium py-3 rounded-xl hover:bg-indigo-700 transition-colors shadow-lg shadow-indigo-200 dark:shadow-none mt-2 flex items-center justify-center gap-2 disabled:opacity-70"
            >
                {isLoading ? (
                    <span className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></span>
                ) : (
                    isLogin ? 'Entrar / Continuar' : 'Criar Conta'
                )}
            </button>
            </form>

            <div className="my-6 flex items-center gap-3">
                <div className="h-px bg-gray-200 dark:bg-gray-700 flex-1"></div>
                <span className="text-xs text-gray-400 font-medium">OU</span>
                <div className="h-px bg-gray-200 dark:bg-gray-700 flex-1"></div>
            </div>

            <button onClick={handleGoogleLogin} className="w-full flex items-center justify-center gap-3 border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 text-gray-700 dark:text-gray-200 py-3 rounded-xl hover:bg-gray-50 dark:hover:bg-gray-700 transition-colors font-medium">
                {isLoading ? (
                    <span className="w-5 h-5 border-2 border-gray-400 border-t-transparent rounded-full animate-spin"></span>
                ) : (
                    <img 
                        src="https://www.gstatic.com/firebasejs/ui/2.0.0/images/auth/google.svg" 
                        alt="Google" 
                        className="w-5 h-5" 
                    />
                )}
                Continuar com Google
            </button>

            <p className="mt-6 text-center text-sm text-gray-600 dark:text-gray-400">
            {isLogin ? 'Não tem uma conta?' : 'Já tem uma conta?'}
            <button
                onClick={() => { setIsLogin(!isLogin); setError(null); }}
                className="ml-1 font-semibold text-indigo-600 hover:text-indigo-800 dark:hover:text-indigo-400 focus:outline-none hover:underline"
            >
                {isLogin ? 'Inscrever-se' : 'Entrar'}
            </button>
            </p>
        </div>
      </div>
    </div>
  );
};

export interface User {
  id: string;
  name: string;
  email: string;
}

export interface Message {
  id: string;
  role: 'user' | 'model';
  text: string;
  image?: string; // Base64 string
  timestamp: number;
}

export interface ChatSession {
  id: string;
  title: string; // Ex: "Resumo de Biologia"
  messages: Message[];
  createdAt: number;
  lastMessageAt: number;
  userId?: string; // ID do utilizador dono da conversa (opcional para visitantes)
}

export interface DocumentData {
  id: string;
  title: string;
  content: string; // HTML string
  createdAt: number;
}

export interface SavedDocument {
  id: string;
  title: string;
  content: string;
  createdAt: number;
  metadata: any;
}

export enum HumanizerVariant {
  PT_PT = 'Português de Portugal',
  PT_AO = 'Português de Angola',
  PT_MZ = 'Português de Moçambique',
}

export enum AppView {
  AUTH = 'AUTH',
  CHAT = 'CHAT',
  STUDIO = 'STUDIO',
  HUMANIZER = 'HUMANIZER',
}

import React, { useState, useEffect, useRef } from 'react';
import { Auth } from './components/Auth';
import { Chat } from './components/Chat';
import { DocumentStudio } from './components/DocumentStudio';
import { HumanizerView } from './components/HumanizerView';
import { User, AppView, ChatSession, Message } from './types';
import { MessageSquare, FileText, LogOut, Menu, LogIn, Plus, Sparkles, Moon, Sun, RotateCcw, Search, PanelLeftClose, PanelLeft, Trash2, MoreHorizontal, Book, Zap, Code, X } from 'lucide-react';

const FREE_USAGE_LIMIT = 6;

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [currentView, setCurrentView] = useState<AppView>(AppView.CHAT);
  const [isSidebarOpen, setIsSidebarOpen] = useState(window.innerWidth > 768);
  const [isAuthModalOpen, setIsAuthModalOpen] = useState(false);
  const [authReason, setAuthReason] = useState<'user_action' | 'limit_reached'>('user_action');
  const [usageCount, setUsageCount] = useState(0);
  const [humanizerInitialText, setHumanizerInitialText] = useState<string>('');

  // Dark Mode State
  const [isDarkMode, setIsDarkMode] = useState(true);

  // Session Management
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [currentSessionId, setCurrentSessionId] = useState<string | null>(null);

  // Ref to track current session ID inside async callbacks (prevents duplication during streaming)
  const currentSessionIdRef = useRef<string | null>(currentSessionId);

  // Helpers para LocalStorage
  const getAllSessionsFromStorage = (): ChatSession[] => {
      try {
          const saved = localStorage.getItem('iv4_chat_sessions');
          return saved ? JSON.parse(saved) : [];
      } catch (e) {
          return [];
      }
  };

  const saveAllSessionsToStorage = (allSessions: ChatSession[]) => {
      localStorage.setItem('iv4_chat_sessions', JSON.stringify(allSessions));
  };

  // Handle Dark Mode Class (Separated to avoid re-triggering initialization)
  useEffect(() => {
    if (isDarkMode) {
        document.documentElement.classList.add('dark');
    } else {
        document.documentElement.classList.remove('dark');
    }
  }, [isDarkMode]);

  // Initialization & Data Loading (Runs once on mount)
  useEffect(() => {
    // Restore User from LocalStorage
    const savedUser = localStorage.getItem('iv4_user');
    let loadedUser = null;
    if (savedUser) {
        try {
            loadedUser = JSON.parse(savedUser);
            setUser(loadedUser);
        } catch (e) {
            console.error("Failed to parse user from local storage");
        }
    }

    // Check usage from local storage
    const savedUsage = localStorage.getItem('iv4_usage_count');
    if (savedUsage) setUsageCount(parseInt(savedUsage));

    // Carregar sessões iniciais filtradas pelo utilizador carregado
    loadFilteredSessions(loadedUser);

    // Iniciar sempre com estado de "Nova Conversa" visualmente
    setCurrentSessionId(null);
  }, []); 

  // Função para carregar e filtrar sessões baseado no utilizador atual
  const loadFilteredSessions = (currentUser: User | null) => {
      const allSessions = getAllSessionsFromStorage();

      const filtered = allSessions.filter(s => {
          if (currentUser) {
              // Se logado, mostra apenas as minhas sessões
              return s.userId === currentUser.id;
          } else {
              // Se visitante, mostra apenas sessões sem userId (criadas como visitante)
              return !s.userId;
          }
      }).sort((a, b) => b.lastMessageAt - a.lastMessageAt);

      setSessions(filtered);
  };

  // Recarregar sessões sempre que o utilizador muda
  useEffect(() => {
      loadFilteredSessions(user);
      // Se a sessão atual não pertencer ao novo utilizador (ou falta dela), resetar para nova conversa
      // Isso evita ver o chat do utilizador anterior por breves momentos
      if (currentSessionId) {
          const allSessions = getAllSessionsFromStorage();
          const session = allSessions.find(s => s.id === currentSessionId);
          if (session) {
              const belongsToUser = user ? session.userId === user.id : !session.userId;
              if (!belongsToUser) {
                  setCurrentSessionId(null);
              }
          }
      }
  }, [user?.id]); // Depender apenas do ID para evitar loops

  // Sync Ref with State
  useEffect(() => {
    currentSessionIdRef.current = currentSessionId;
  }, [currentSessionId]);

  // Handle window resize for responsive sidebar
  useEffect(() => {
      const handleResize = () => {
          if (window.innerWidth > 768) {
              setIsSidebarOpen(true);
          } else {
              setIsSidebarOpen(false);
          }
      };
      window.addEventListener('resize', handleResize);
      return () => window.removeEventListener('resize', handleResize);
  }, []);

  const startNewChat = () => {
      setCurrentSessionId(null);
      setCurrentView(AppView.CHAT);
      if (window.innerWidth < 768) setIsSidebarOpen(false);
  };

  const deleteSession = (e: React.MouseEvent, id: string) => {
      e.stopPropagation();

      // 1. Carregar TUDO do storage
      const allSessions = getAllSessionsFromStorage();

      // 2. Filtrar removendo a sessão alvo
      const updatedAll = allSessions.filter(s => s.id !== id);

      // 3. Guardar TUDO de volta
      saveAllSessionsToStorage(updatedAll);

      // 4. Atualizar a visualização local
      loadFilteredSessions(user);

      // Se apagámos a sessão ativa, resetar para nova conversa
      if (currentSessionId === id) {
          setCurrentSessionId(null);
      }
  };

  const handleSessionUpdate = (messages: Message[]) => {
      const activeId = currentSessionIdRef.current;
      const allSessions = getAllSessionsFromStorage();
      let updatedAllSessions = [...allSessions];

      if (activeId) {
          // Update existing session
          const sessionIndex = updatedAllSessions.findIndex(s => s.id === activeId);

          if (sessionIndex !== -1) {
              // Gerar título se for 'Nova Conversa'
              let newTitle = updatedAllSessions[sessionIndex].title;
              if ((newTitle === 'Nova Conversa' || !newTitle) && messages.length > 0) {
                  const firstUserMsg = messages.find(m => m.role === 'user');
                  if (firstUserMsg) {
                      newTitle = firstUserMsg.text.slice(0, 30) + (firstUserMsg.text.length > 30 ? '...' : '');
                  }
              }

              updatedAllSessions[sessionIndex] = {
                  ...updatedAllSessions[sessionIndex],
                  messages,
                  title: newTitle,
                  lastMessageAt: Date.now(),
                  userId: user?.id // Garante que se o user logou entretanto, a sessão fica atualizada
              };
          }
      } else {
          // Create NEW session
          const newId = Date.now().toString();
          currentSessionIdRef.current = newId; 

          let newTitle = 'Nova Conversa';
          if (messages.length > 0) {
               const firstUserMsg = messages.find(m => m.role === 'user');
               if (firstUserMsg) {
                    newTitle = firstUserMsg.text.slice(0, 30) + (firstUserMsg.text.length > 30 ? '...' : '');
               }
          }

          const newSession: ChatSession = {
              id: newId,
              title: newTitle,
              messages: messages,
              createdAt: Date.now(),
              lastMessageAt: Date.now(),
              userId: user?.id // Associa ao utilizador se logado
          };

          updatedAllSessions = [newSession, ...updatedAllSessions];
          setCurrentSessionId(newId);
      }

      // Guardar no Storage Global e Atualizar View Local
      saveAllSessionsToStorage(updatedAllSessions);

      // Filtra para o estado local baseado no user atual
      const filtered = updatedAllSessions.filter(s => {
          if (user) return s.userId === user.id;
          return !s.userId;
      }).sort((a, b) => b.lastMessageAt - a.lastMessageAt);

      setSessions(filtered);
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('iv4_user');
    setCurrentSessionId(null);
    setCurrentView(AppView.CHAT);
    // useEffect do [user] vai tratar de recarregar as sessões de visitante
  };

  const handleLoginSuccess = (loggedInUser: User) => {
    // Lógica ChatGPT: Se eu tenho uma conversa ativa como visitante e faço login,
    // essa conversa passa a ser do meu utilizador novo.
    if (currentSessionId) {
        const allSessions = getAllSessionsFromStorage();
        const sessionIndex = allSessions.findIndex(s => s.id === currentSessionId);

        if (sessionIndex !== -1 && !allSessions[sessionIndex].userId) {
            // Migrar sessão de visitante para o novo utilizador
            allSessions[sessionIndex].userId = loggedInUser.id;
            saveAllSessionsToStorage(allSessions);
        }
    }

    setUser(loggedInUser);
    localStorage.setItem('iv4_user', JSON.stringify(loggedInUser));
    setIsAuthModalOpen(false);
    setAuthReason('user_action');
    // useEffect do [user] vai recarregar a lista correta
  };

  const checkUsageLimit = (): boolean => {
    if (user) return true;

    if (usageCount >= FREE_USAGE_LIMIT) {
      setAuthReason('limit_reached');
      setIsAuthModalOpen(true);
      return false;
    }

    const newCount = usageCount + 1;
    setUsageCount(newCount);
    localStorage.setItem('iv4_usage_count', newCount.toString());
    return true;
  };

  const handleHumanizeRequest = (text: string) => {
    setHumanizerInitialText(text);
    setCurrentView(AppView.HUMANIZER);
  };

  // Buscar sessão ativa da lista filtrada
  const getCurrentSession = () => sessions.find(s => s.id === currentSessionId);

  return (
    <div className="flex h-screen bg-gray-50 dark:bg-[#030712] text-gray-900 dark:text-gray-100 font-sans overflow-hidden transition-colors duration-300">

      <Auth 
        isOpen={isAuthModalOpen} 
        onClose={() => setIsAuthModalOpen(false)} 
        onLogin={handleLoginSuccess}
        triggerReason={authReason}
      />

      {/* Sidebar - Old Interface Layout */}
      {/* Mobile Overlay Background */}
      {isSidebarOpen && window.innerWidth < 768 && (
          <div 
            className="fixed inset-0 bg-black/50 z-20"
            onClick={() => setIsSidebarOpen(false)}
          ></div>
      )}

      <aside 
        className={`fixed md:relative top-0 left-0 h-full bg-white dark:bg-[#020617] border-r border-gray-200 dark:border-white/5 transition-all duration-300 ease-in-out z-30 w-[280px] flex flex-col ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full md:w-0 md:translate-x-0 md:hidden'}`}
      >
        <div className="p-4 flex flex-col h-full relative">

            {/* Mobile Close Button */}
            <button 
                onClick={() => setIsSidebarOpen(false)}
                className="md:hidden absolute top-4 right-4 text-gray-400"
            >
                <X size={20} />
            </button>

            {/* Logo */}
            <div className="flex items-center gap-3 mb-6 px-2">
                <div className="p-1.5 bg-[#4f46e5] rounded-lg shadow-lg shadow-indigo-500/20">
                    <Sparkles className="text-white" size={18} />
                </div>
                <span className="font-bold text-lg tracking-tight text-gray-900 dark:text-white">IV4 IA</span>
            </div>

            {/* New Chat Button */}
            <button 
                onClick={startNewChat}
