import { GoogleGenAI } from "@google/genai";
import { HumanizerVariant } from "../types";

// Função auxiliar para obter o cliente de forma segura e "lazy" (apenas quando necessário)
const getAiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API_KEY_MISSING");
  }
  return new GoogleGenAI({ apiKey });
};

// Função auxiliar para esperar (delay)
const wait = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

// Wrapper genérico para Retry com Exponential Backoff
// ATUALIZADO: Aumentado para 10 tentativas padrão e delay inicial de 5s para cobrir janelas de 60s+ do Google
async function withRetry<T>(operation: () => Promise<T>, retries = 10, initialDelay = 5000): Promise<T> {
    let lastError: any;

    for (let i = 0; i < retries; i++) {
        try {
            return await operation();
        } catch (error: any) {
            lastError = error;

            // Verifica códigos de erro comuns para Rate Limit (429) ou Serviço Indisponível (503)
            const isRateLimit = error.code === 429 || error.status === 429 || error.message?.includes('429') || error.message?.includes('Quota exceeded');
            const isServerOverload = error.code === 503 || error.status === 503;

            if (isRateLimit || isServerOverload) {
                // Se for a última tentativa, não espera, deixa falhar
                if (i === retries - 1) break;

                // Exponential Backoff com um teto máximo de 30 segundos por espera para não ficar infinito
                // 5s, 10s, 20s, 30s, 30s, 30s...
                const calcDelay = initialDelay * Math.pow(2, i);
                const delay = Math.min(calcDelay, 30000); 

                console.warn(`[IV4 IA] Limite de tráfego (Rate Limit 429). A aguardar ${delay/1000}s para tentar novamente... (Tentativa ${i + 1}/${retries})`);
                await wait(delay);
                continue;
            }

            // Se for outro erro (ex: 400 Bad Request), falha imediatamente
            throw error;
        }
    }
    throw lastError;
}

export const GeminiService = {
  /**
   * Chat com a IA com suporte a streaming, Thinking Mode e Google Search dinâmicos.
   */
  async chatStream(
      history: { role: string; parts: { text?: string; inlineData?: any }[] }[], 
      message: string, 
      onChunk: (text: string) => void,
      mediaBase64?: string, 
      mediaType?: string,
      signal?: AbortSignal,
      config?: { isThinking?: boolean; isSearch?: boolean }
  ): Promise<void> {
    try {
      // Inicializa o cliente apenas aqui
      const ai = getAiClient();

      // Obtém a data e hora atual dinamicamente
      const now = new Date();
      const options: Intl.DateTimeFormatOptions = { 
        weekday: 'long', 
        year: 'numeric', 
        month: 'long', 
        day: 'numeric',
        hour: '2-digit', 
        minute: '2-digit'
      };
      const currentFullDate = now.toLocaleDateString('pt-PT', options);
      const currentYear = now.getFullYear();

      // Instrução de sistema dinâmica com foco temporal e FACTOS RECENTES DE MOÇAMBIQUE
      const systemInstruction = `
        Você é o IV4 IA, um assistente de inteligência artificial avançado.

        == CONTEXTO TEMPORAL OBRIGATÓRIO ==
        HOJE É: ${currentFullDate}.
        ANO ATUAL: ${currentYear}.

        == FACTOS ATUALIZADOS (MOÇAMBIQUE) ==
        - Presidente da República: Daniel Chapo (Eleito para suceder Filipe Nyusi).
        - Partido no poder: FRELIMO.
        - IMPORTANTE: O atual Presidente é Daniel Chapo. Se o usuário perguntar, confirme isso.

        == INFORMAÇÕES SOBRE ORIGEM ==
        (Apenas se perguntado explicitamente sobre quem te criou ou a empresa):
        - Criador: Ivo Nunes Jaime.
        - Ano de criação: 2025.
        - Local: Niassa, Lichinga, Moçambique.

        == COMPORTAMENTO ==
        - Responda de forma fluida, natural e direta.
        - ${config?.isSearch ? 'Utilize a ferramenta de busca (Google Search) para obter informações atualizadas se necessário.' : 'Use seu conhecimento interno para responder.'}
        - NÃO adicione listas de links ou fontes no final da resposta a menos que seja explicitamente pedido.
        - Seja útil, académico e educado.
        - **Utilize emojis de forma inteligente e moderada para tornar a conversa amigável e expressiva.** 🚀😊
        - Idioma: Português (variante Moçambique preferencial).
      `;

      // Configuração dinâmica de Tools e Thinking
      const tools: any[] = [];
      if (config?.isSearch) {
        tools.push({ googleSearch: {} });
      }

      const modelConfig: any = {
        systemInstruction: systemInstruction,
      };

      if (tools.length > 0) {
        modelConfig.tools = tools;
      }

      // Thinking Config (apenas se ativado)
      if (config?.isThinking) {
        // Aumentado para 24576 (max para Flash) para permitir raciocínio profundo em tarefas complexas
        modelConfig.thinkingConfig = { thinkingBudget: 24576 }; 
      }

      // Cria a sessão de chat
      const chat = ai.chats.create({
        model: 'gemini-2.5-flash',
        history: history,
        config: modelConfig
      });

      // Envolvemos a chamada de envio em Retry com configurações agressivas
      await withRetry(async () => {
          let responseStream;

          if (mediaBase64 && mediaType) {
            // Tratamento de imagem
            const base64Data = mediaBase64.includes(',') 
                ? mediaBase64.split(',')[1] 
                : mediaBase64;

            responseStream = await chat.sendMessageStream({
                message: [
                    { text: message },
                    { inlineData: { data: base64Data, mimeType: mediaType } }
                ]
            });
          } else {
            responseStream = await chat.sendMessageStream({ message: message });
          }

          // Loop de streaming
          for await (const chunk of responseStream) {
            if (signal?.aborted) {
                break;
            }

            const text = chunk.text;
            if (text) {
                onChunk(text);
            }
          }
      }, 10, 5000); // 10 Tentativas, começa com 5s. Cobre ~4 minutos de falha.

    } catch (error: any) {
      console.error("Chat Stream Error:", error);

      if (error.message === "API_KEY_MISSING") {
         throw error; // Repassa erro de chave para o componente tratar
      }

      // Se for erro de bloqueio ou rede, tenta avisar com DETALHES
      if (!signal?.aborted) {
         let errorDetails = error.message || error.toString();

         if (errorDetails.includes('429') || errorDetails.includes('Quota exceeded')) {
             errorDetails = "O tráfego está muito alto no momento (Quota Google Esgotada). Por favor, aguarde 1 ou 2 minutos e tente novamente. O sistema tentou reconectar automaticamente várias vezes sem sucesso.";
         }

         // Mensagem amigável mas técnica o suficiente para debug
         onChunk(`\n\n⚠️ **Erro de Conexão:** ${errorDetails}`);
      }
    }
  },

  /**
   * Wrapper para chamadas sem necessidade de UI streaming, mas usando a lógica unificada.
   */
  async chat(
      history: { role: string; parts: { text?: string; inlineData?: any }[] }[], 
      message: string, 
      mediaBase64?: string, 
      mediaType?: string, 
      signal?: AbortSignal
  ): Promise<string> {
    let fullText = "";
    await this.chatStream(
        history, 
        message, 
        (chunk) => { fullText += chunk; }, 
        mediaBase64, 
        mediaType, 
        signal
    );
    return fullText;
  },

