      history: { role: string; parts: { text?: string; inlineData?: any }[] }[], 
      message: string, 
      mediaBase64?: string, 
      mediaType?: string, 
      signal?: AbortSignal
  ): Promise<string> {
    let fullText = "";
    await this.chatStream(
        history, 
        message, 
        (chunk) => { fullText += chunk; }, 
        mediaBase64, 
        mediaType, 
        signal
    );
    return fullText;
  },

